7443: inline simdjson_result<element> element::at_pointer(std::string_view json_pointer) const noexcept {
7444:   SIMDJSON_DEVELOPMENT_ASSERT(tape.usable()); // https://github.com/simdjson/simdjson/issues/1914
7445:   switch (tape.tape_ref_type()) {
7446:     case internal::tape_type::START_OBJECT:
7447:       return object(tape).at_pointer(json_pointer);
7448:     case internal::tape_type::START_ARRAY:
7449:       return array(tape).at_pointer(json_pointer);
7450:     default: {
7451:       if(!json_pointer.empty()) { // a non-empty string is invalid on an atom
7452:         return INVALID_JSON_POINTER;
7453:       }
7454:       // an empty string means that we return the current node
7455:       dom::element copy(*this);
7456:       return simdjson_result<element>(std::move(copy));
7457:     }
7458:   }
