117:   SIMDJSON_DEVELOPMENT_ASSERT(tape.usable()); // https://github.com/simdjson/simdjson/issues/1914
118:   size_t i=0;
119:   for (auto element : *this) {
120:     if (i == index) { return element; }
121:     i++;
122:   }
