#include "simdjson.h"
#include <iostream>
int main() {
  simdjson::padded_string json = R"({"document":{"key4":40}})"_padded;
  simdjson::dom::parser parser;
  auto doc = parser.parse(json);
  auto e = doc.at_pointer("/document/key4/sub");
  if (e.error() != simdjson::NO_SUCH_FIELD) { std::cerr << "dom " << e.error() << "\n"; return 1; }
  auto bad = doc.at_pointer("/document/key4/~2");
  if (bad.error() != simdjson::INVALID_JSON_POINTER) { std::cerr << "dom bad " << bad.error() << "\n"; return 4; }
  simdjson::ondemand::parser oparser;
  auto odoc = oparser.iterate(json);
  auto v = odoc.at_pointer("/document/key4/sub");
  if (v.error() != simdjson::NO_SUCH_FIELD) { std::cerr << "ondemand " << v.error() << "\n"; return 2; }
  simdjson::ondemand::parser badparser;
  auto bdoc = badparser.iterate(json);
  auto bv = bdoc.at_pointer("/document/key4/~2");
  if (bv.error() != simdjson::INVALID_JSON_POINTER) { std::cerr << "ondemand bad " << bv.error() << "\n"; return 5; }
  simdjson::padded_string scalar = "1"_padded;
  simdjson::ondemand::parser sparser;
  auto sdoc = sparser.iterate(scalar);
  auto sv = sdoc.at_pointer("not/a/pointer");
  if (sv.error() != simdjson::INVALID_JSON_POINTER) { std::cerr << "syntax " << sv.error() << "\n"; return 3; }
  return 0;
}
